            {item}
          </div>
        ))}
      </div>

      <InfiniteScroll onReachBottom={loadMore} hasMore={hasMore} loading={loading} />

      {!hasMore && <p className="text-center text-text-secondary text-sm mt-4">— You've reached the end —</p>}
    </div>
  );
};

